// ────────────────────────────────────────────────────
async function seed() {
  console.log(`Seeding ${TEMPLES.length} temples into Supabase...`);
  
  // First, check existing count
  const { count } = await supabase.from('temples').select('*', { count: 'exact', head: true });
  console.log(`Current row count: ${count}`);

  // Add hue + convert major_festivals to array (Supabase column is text[])
  const rows = TEMPLES.map(t => ({
    ...t,
    hue: hueFromDeity(t.deity_primary),
    major_festivals: typeof t.major_festivals === 'string'
      ? t.major_festivals.split(',').map(s => s.trim()).filter(Boolean)
      : (t.major_festivals || []),
    image_urls: t.image_urls || [],
  }));

  // Insert in batches of 25
  let inserted = 0;
  for (let i = 0; i < rows.length; i += 25) {
    const batch = rows.slice(i, i + 25);
    const { data, error } = await supabase.from('temples').insert(batch).select('id');
    if (error) {
      console.error(`Batch ${i / 25 + 1} error:`, error.message);
    } else {
      inserted += data.length;
      process.stdout.write(`  Inserted ${inserted}/${rows.length}\r`);
    }
  }
  console.log(`\nDone! Inserted ${inserted} temples.`);
  
  // Verify
  const { count: final } = await supabase.from('temples').select('*', { count: 'exact', head: true });
  console.log(`Final row count: ${final}`);
}

seed().catch(e => { console.error(e); process.exit(1); });
